input:
interface ValidatedDetails {
  protocol: number;
  patchLevel: Array<'linear' | 'exponential' | 'fibonacci'>;
  progress: number;
  majorVersion: 'pending' | 'active' | 'done';
  width: 'none' | 'partial' | 'full';
  bytesSent?: 'input' | 'output' | 'bidirectional';
  id: string | null;
  confidence: 'A' | 'AAAA' | 'CNAME' | 'MX' | 'TXT' | 'SRV';
  column_name: Array<'file' | 'git' | 'webhook' | 'schedule' | 'cron'>;
  version: string[];
}

output:
ValidatedDetails
  = protocol:ProtocolSection EOL patchLevel:PatchLevelSection EOL progress:ProgressSection EOL majorVersion:MajorVersionSection EOL width:WidthSection EOL id:IdSection EOL confidence:ConfidenceSection EOL column_name:ColumnNameSection EOL version:VersionSection bytesSent:BytesSentOpt EOLopt
    { return { protocol: protocol, patchLevel: patchLevel, progress: progress, majorVersion: majorVersion, width: width, id: id, confidence: confidence, column_name: column_name, version: version, bytesSent: bytesSent }; }

ProtocolSection
  = "PROTOCOL:" _ v:Integer { return v; }

PatchLevelSection
  = "PATCH_LEVEL:" _ "none" { return []; }
  / "PATCH_LEVEL:" _ first:PatchLevelValue rest:("," _ v:PatchLevelValue { return v; })* { return [first, ...rest]; }

PatchLevelValue
  = "linear" / "exponential" / "fibonacci"

ProgressSection
  = "PROGRESS:" _ v:Float { return v; }

MajorVersionSection
  = "MAJOR_VERSION:" _ v:("pending" / "active" / "done") { return v; }

WidthSection
  = "WIDTH:" _ v:("none" / "partial" / "full") { return v; }

IdSection
  = "ID:" _ "none" { return null; }
  / "ID:" _ v:QuotedString { return v; }

ConfidenceSection
  = "CONFIDENCE:" _ v:("A" / "AAAA" / "CNAME" / "MX" / "TXT" / "SRV") { return v; }

ColumnNameSection
  = "COLUMN_NAME:" _ "none" { return []; }
  / "COLUMN_NAME:" _ first:ColumnNameValue rest:("," _ v:ColumnNameValue { return v; })* { return [first, ...rest]; }

ColumnNameValue
  = "file" / "git" / "webhook" / "schedule" / "cron"

VersionSection
  = "VERSION:" _ "none" { return []; }
  / "VERSION:" _ first:Identifier rest:("," _ id:Identifier { return id; })* { return [first, ...rest]; }

BytesSentOpt
  = EOL "BYTES_SENT:" _ v:("input" / "output" / "bidirectional") { return v; }
  / "" { return undefined; }

Identifier = chars:$[a-zA-Z0-9_-]+ { return chars; }
QuotedString = '"' chars:$[^"]* '"' { return chars; }
Float = chars:$([0-9]+ ("." [0-9]+)?) { return parseFloat(chars); }
Integer = chars:$[0-9]+ { return parseInt(chars, 10); }
_ = [ \t]*
EOL = _ "\n"
EOLopt = (_ "\n")?

